@namespace Lumeo

@{
    var context = new RadioGroupContext(Value, EventCallback.Factory.Create<string>(this, OnValueSelected), _itemValues, _itemIds, _itemDisabled);
}

@if (Label is not null && !InsideFormField)
{
    <label class="text-sm font-medium leading-none">
        @Label
        @if (Required)
        {
            <span class="text-destructive ml-0.5">*</span>
        }
    </label>
}

<div role="radiogroup"
     aria-label="@AriaLabel"
     aria-labelledby="@AriaLabelledBy"
     aria-required="@Required.ToString().ToLower()"
     aria-invalid="@EffectiveInvalid.ToString().ToLower()"
     class="@CssClass"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && ErrorText is not null)
    {
        <p class="text-xs text-destructive">@ErrorText</p>
    }
    else if (HelperText is not null)
    {
        <p class="text-xs text-muted-foreground">@HelperText</p>
    }
}

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string> ValueChanged { get; set; }
    [Parameter] public string? AriaLabel { get; set; }
    [Parameter] public string? AriaLabelledBy { get; set; }
    /// <summary>Per-group density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Only the inter-option row gap
    /// shifts between values.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly List<string> _itemValues = new();
    private readonly Dictionary<string, string> _itemIds = new();
    private readonly Dictionary<string, bool> _itemDisabled = new();

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    // Inter-option gap tracks density; Comfortable reproduces the historical gap-2.
    private string GapClass => EffectiveDensity switch
    {
        Lumeo.Density.Compact => "gap-1",
        Lumeo.Density.Spacious => "gap-3",
        _ => "gap-2"
    };

    private string CssClass => Cx.Merge("grid", GapClass, (EffectiveInvalid ? "text-destructive" : ""), Class);

    private async Task OnValueSelected(string value)
    {
        Value = value;
        await ValueChanged.InvokeAsync(value);
    }

    public record RadioGroupContext(
        string? Value,
        EventCallback<string> OnSelect,
        List<string> ItemValues,
        Dictionary<string, string> ItemIds,
        Dictionary<string, bool> ItemDisabled);
}

@namespace Lumeo
@implements IAsyncDisposable

<button type="button"
        id="@_itemId"
        role="radio"
        aria-checked="@IsSelected.ToString().ToLower()"
        tabindex="@Tabindex"
        class="@CssClass"
        @onclick="Select"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
    @ChildContent
</button>

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public RadioGroup.RadioGroupContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("radio-card");
    private string? _registeredValue;
    private bool IsSelected => Context.Value == Value;

    private int Tabindex
    {
        get
        {
            if (Context.Value == Value) return 0;
            if (string.IsNullOrEmpty(Context.Value)
                && Context.ItemValues.FirstOrDefault(v => !IsItemDisabled(v)) == Value) return 0;
            return -1;
        }
    }

    private bool IsItemDisabled(string value) =>
        Context.ItemDisabled.TryGetValue(value, out var d) && d;

    private string CssClass => Cx.Merge(
        "flex cursor-pointer rounded-lg border-2 p-4 text-left transition-colors hover:bg-accent/60 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2",
        IsSelected ? "border-primary bg-primary/5" : "border-border/40",
        Class);

    protected override void OnParametersSet()
    {
        // Ownership-guarded re-key (see RadioGroupItem) + idempotent register.
        if (_registeredValue is not null && _registeredValue != Value
            && Context.ItemIds.TryGetValue(_registeredValue, out var oldId) && oldId == _itemId)
        {
            Context.ItemValues.Remove(_registeredValue);
            Context.ItemIds.Remove(_registeredValue);
            Context.ItemDisabled.Remove(_registeredValue);
        }
        if (!Context.ItemValues.Contains(Value))
            Context.ItemValues.Add(Value);
        Context.ItemIds[Value] = _itemId;
        Context.ItemDisabled[Value] = false;
        _registeredValue = Value;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            await Interop.RegisterPreventDefaultKeys(
                _itemId,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft" }
                    .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;

    private async Task Select() => await Context.OnSelect.InvokeAsync(Value);

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // No Space branch: the native <button> click already runs Select.
        var items = Context.ItemValues;
        var idx = items.IndexOf(Value);

        var direction = e.Key switch
        {
            "ArrowDown" or "ArrowRight" => 1,
            "ArrowUp" or "ArrowLeft" => -1,
            _ => 0
        };
        if (direction == 0) return;

        var nextValue = FindNextEnabled(items, idx, direction);
        if (nextValue is not null)
        {
            await Context.OnSelect.InvokeAsync(nextValue);
            if (Context.ItemIds.TryGetValue(nextValue, out var nextId))
            {
                await Interop.FocusElement(nextId);
            }
        }
    }

    private string? FindNextEnabled(List<string> items, int currentIdx, int direction)
    {
        if (items.Count == 0) return null;
        var idx = currentIdx;
        for (var i = 0; i < items.Count; i++)
        {
            idx += direction;
            if (idx < 0) idx = items.Count - 1;
            else if (idx >= items.Count) idx = 0;
            if (idx == currentIdx) return null;
            if (!IsItemDisabled(items[idx])) return items[idx];
        }
        return null;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registeredValue is not null
            && Context.ItemIds.TryGetValue(_registeredValue, out var id) && id == _itemId)
        {
            Context.ItemValues.Remove(_registeredValue);
            Context.ItemIds.Remove(_registeredValue);
            Context.ItemDisabled.Remove(_registeredValue);
        }
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_itemId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}

@namespace Lumeo
@implements IAsyncDisposable

@if (!string.IsNullOrEmpty(Description))
{
    <div class="flex items-start gap-2">
        <button type="button"
                id="@_itemId"
                role="radio"
                aria-checked="@IsSelected.ToString().ToLower()"
                aria-label="@EffectiveAriaLabel"
                tabindex="@Tabindex"
                class="@CssClass"
                @onclick="Select"
                @onkeydown="HandleKeyDown"
                disabled="@Disabled"
                @attributes="AdditionalAttributes">
            @if (IsSelected)
            {
                <span class="flex h-2 w-2 rounded-full bg-current"></span>
            }
        </button>
        <div class="grid gap-0.5 leading-none">
            @if (ChildContent is not null)
            {
                @ChildContent
            }
            <p class="text-xs text-muted-foreground mt-0.5">@Description</p>
        </div>
    </div>
}
else
{
    <button type="button"
            id="@_itemId"
            role="radio"
            aria-checked="@IsSelected.ToString().ToLower()"
            aria-label="@EffectiveAriaLabel"
            tabindex="@Tabindex"
            class="@CssClass"
            @onclick="Select"
            @onkeydown="HandleKeyDown"
            disabled="@Disabled"
            @attributes="AdditionalAttributes">
        @if (IsSelected)
        {
            <span class="flex h-2 w-2 rounded-full bg-current"></span>
        }
    </button>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public RadioGroup.RadioGroupContext Context { get; set; } = default!;
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Description { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? AriaLabel { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("radio");

    // Fall back to Value so screen readers always have a name when no external
    // label element is associated (i.e. when RadioGroupItem is used standalone
    // without a sibling <label> or ChildContent that provides the label text).
    private string EffectiveAriaLabel => !string.IsNullOrEmpty(AriaLabel) ? AriaLabel : Value;
    private bool IsSelected => Context.Value == Value;

    private int Tabindex
    {
        get
        {
            if (Context.Value == Value) return 0;
            // No selection yet: the first ENABLED radio is the tab stop.
            if (string.IsNullOrEmpty(Context.Value)
                && Context.ItemValues.FirstOrDefault(v => !IsItemDisabled(v)) == Value) return 0;
            return -1;
        }
    }

    private bool IsItemDisabled(string value) =>
        Context.ItemDisabled.TryGetValue(value, out var d) && d;

    private string CssClass => Cx.Merge("aspect-square h-4 w-4 shrink-0 cursor-pointer rounded-full border border-primary text-primary focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50 flex items-center justify-center", Class);

    protected override void OnParametersSet()
    {
        // Registered every parameter set (idempotent) so Disabled changes stay
        // current for sibling arrow navigation; ownership-guarded re-key when
        // Value changes so we never delete a sibling's live registration.
        if (_registeredValue is not null && _registeredValue != Value
            && Context.ItemIds.TryGetValue(_registeredValue, out var oldId) && oldId == _itemId)
        {
            Context.ItemValues.Remove(_registeredValue);
            Context.ItemIds.Remove(_registeredValue);
            Context.ItemDisabled.Remove(_registeredValue);
        }
        if (!Context.ItemValues.Contains(Value))
            Context.ItemValues.Add(Value);
        Context.ItemIds[Value] = _itemId;
        Context.ItemDisabled[Value] = Disabled;
        _registeredValue = Value;
    }

    private string? _registeredValue;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;
        try
        {
            // Key-selective preventDefault: the former render-time _preventKey
            // flag lagged one event — the first arrow press scrolled the page.
            await Interop.RegisterPreventDefaultKeys(
                _itemId,
                new[] { "ArrowDown", "ArrowRight", "ArrowUp", "ArrowLeft" }
                    .Select(k => new Lumeo.Services.PreventDefaultKeyRule(k)).ToArray());
            _pdRegistered = true;
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { } // JS interop unavailable during prerender
    }

    private bool _pdRegistered;

    private async Task Select()
    {
        if (!Disabled)
        {
            await Context.OnSelect.InvokeAsync(Value);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // Space is NOT handled here: on a native <button> the browser
        // synthesizes a click which already runs Select — the old explicit
        // branch double-fired OnSelect.
        var items = Context.ItemValues;
        var idx = items.IndexOf(Value);

        var direction = e.Key switch
        {
            "ArrowDown" or "ArrowRight" => 1,
            "ArrowUp" or "ArrowLeft" => -1,
            _ => 0
        };
        if (direction == 0 || Disabled) return;

        // WAI-ARIA radio group: arrows skip disabled radios (selecting one
        // was possible before because only the CURRENT item was checked).
        var nextValue = FindNextEnabled(items, idx, direction);
        if (nextValue is not null)
        {
            await Context.OnSelect.InvokeAsync(nextValue);
            if (Context.ItemIds.TryGetValue(nextValue, out var nextId))
            {
                await Interop.FocusElement(nextId);
            }
        }
    }

    private string? FindNextEnabled(List<string> items, int currentIdx, int direction)
    {
        if (items.Count == 0) return null;
        var idx = currentIdx;
        for (var i = 0; i < items.Count; i++)
        {
            idx += direction;
            if (idx < 0) idx = items.Count - 1;
            else if (idx >= items.Count) idx = 0;
            if (idx == currentIdx) return null;
            if (!IsItemDisabled(items[idx])) return items[idx];
        }
        return null;
    }

    public async ValueTask DisposeAsync()
    {
        // Conditionally-removed radios must leave the registry (ownership-
        // guarded — see OnParametersSet).
        if (_registeredValue is not null
            && Context.ItemIds.TryGetValue(_registeredValue, out var id) && id == _itemId)
        {
            Context.ItemValues.Remove(_registeredValue);
            Context.ItemIds.Remove(_registeredValue);
            Context.ItemDisabled.Remove(_registeredValue);
        }
        if (!_pdRegistered) return;
        try
        {
            await Interop.UnregisterPreventDefaultKeys(_itemId);
        }
        catch (JSDisconnectedException) { }
        catch (ObjectDisposedException) { }
        catch (InvalidOperationException) { }
    }
}
